// 스케줄(월 10:00) -> 최근 14일, 웹훅 -> body.days 참조
let body = {};
try { body = $('수동 조회').first().json.body || {}; } catch(e) {}
const chatId = String(body.chatId || body.chat_id || '7713811206');
const days = parseInt(body.days || '14');

const now = new Date();
const kstNow = new Date(now.getTime() + 9 * 60 * 60 * 1000);

const yesterday = new Date(kstNow);
yesterday.setDate(yesterday.getDate() - 1);

const startDate = new Date(yesterday);
startDate.setDate(startDate.getDate() - days + 1);

const fmt = (d) => d.toISOString().slice(0, 10);

const dates = [];
const cur = new Date(startDate);
while (cur <= yesterday) {
  dates.push(fmt(cur));
  cur.setDate(cur.getDate() + 1);
}

// 11번가 클레임 기간 (최근 7일, 주간 실행과 일치시켜 중복 방지)
const claimEnd = new Date(yesterday);
const claimStart = new Date(claimEnd);
claimStart.setDate(claimStart.getDate() - 6);

return [{ json: {
  chatId, days,
  startStr: fmt(startDate),
  endStr: fmt(yesterday),
  dates,
  claimStartStr: fmt(claimStart).replace(/-/g, '') + '0000',
  claimEndStr: fmt(claimEnd).replace(/-/g, '') + '2359'
} }];

// 메이크샵 14일 재조회: status=Y(결제완료)만 집계

const isPersonalPaymentOrder = (entry) => {
  const products = entry && entry.product ? entry.product : {};
  const list = Array.isArray(products) ? products : Object.values(products || {});
  const pattern = /개인\s*결제|개별\s*결제|개인\s*결재|개별\s*결재|개인결제|개별결제|개인결재|개별결재/i;
  for (const p of list) {
    const cate1 = String((p && p.product_cate1) || '');
    const brand = String((p && p.brandcode) || '');
    // PRESSCO21 개인결제 전용 카테고리: 097 / brandcode 097001...
    if (cate1 === '097' || brand.indexOf('097001') === 0) return true;
    const text = String((p && p.product_name) || '') + ' ' + String((p && p.option_data) || '') + ' ' + String((p && p.custom_option_data) || '');
    if (pattern.test(text)) return true;
  }
  return false;
};

const dateInfo = $('날짜 계산').first().json;
const shopkey = $env.MAKESHOP_SHOPKEY || '';
const licensekey = $env.MAKESHOP_LICENSEKEY || '';
const result = {};

if (!shopkey || !licensekey) {
  return [{ json: { makeshop: result, error: 'MAKESHOP 환경변수 미설정' } }];
}

for (const dt of dateInfo.dates) {
  try {
    let resp = await this.helpers.httpRequest({
      method: 'GET',
      url: 'http://foreverlove.co.kr/list/open_api.html',
      qs: {
        mode: 'search', type: 'order', ver: '2',
        InquiryTimeFrom: dt + ' 00:00:00',
        InquiryTimeTo: dt + ' 23:59:59',
        limit: '500'
      },
      headers: { Shopkey: shopkey, Licensekey: licensekey },
      timeout: 15000
    });

    if (typeof resp === 'string') { try { resp = JSON.parse(resp); } catch(e) { resp = {}; } }
    if (resp && typeof resp.data === 'string') { try { resp = JSON.parse(resp.data); } catch(e) {} }
    const rawList = resp && resp.list
      ? (Array.isArray(resp.list) ? resp.list : Object.values(resp.list))
      : [];

    let revenue = 0, orders = 0, personalExcluded = 0;
    for (const entry of rawList) {
      const o = entry.order || entry;
      if (String(o.order_status || o.ord_state || '') !== 'Y') continue;
      const amount = parseInt(o.pay_price || o.total_product_price || 0);
      if (isPersonalPaymentOrder(entry)) { personalExcluded += amount; continue; }
      revenue += amount;
      orders++;
    }
    result[dt] = { revenue, orders, personalExcluded };
  } catch(e) {
    result[dt] = { revenue: -1, orders: -1, error: e.message };
  }
}

return [{ json: { makeshop: result } }];

// 네이버 커머스 API: bcrypt 서명 + 토큰 발급
const bcrypt = require('bcryptjs');
const clientId = $env.NAVER_COMMERCE_CLIENT_ID || '';
const clientSecret = $env.NAVER_COMMERCE_CLIENT_SECRET || '';

if (!clientId || !clientSecret) {
  return [{ json: { error: 'NAVER_COMMERCE 환경변수 미설정', accessToken: '' } }];
}

try {
  const timestamp = Date.now();
  const password = clientId + '_' + timestamp;
  const hashed = bcrypt.hashSync(password, clientSecret);
  const signature = Buffer.from(hashed).toString('base64');

  const tokenData = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.commerce.naver.com/external/v1/oauth2/token',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: 'client_id=' + encodeURIComponent(clientId) + '&timestamp=' + timestamp + '&client_secret_sign=' + encodeURIComponent(signature) + '&grant_type=client_credentials&type=SELF'
  });

  if (!tokenData.access_token) {
    return [{ json: { error: 'Token: ' + JSON.stringify(tokenData).slice(0, 200), accessToken: '' } }];
  }
  return [{ json: { accessToken: tokenData.access_token, error: '' } }];
} catch (e) {
  return [{ json: { error: 'Naver auth ' + e.message, accessToken: '' } }];
}

// 네이버 14일 재조회: 취소/반품 상태 제외
const dateInfo = $('날짜 계산').first().json;
const token = $('네이버 인증').first().json.accessToken || '';
const CANCEL = ['CANCELED','RETURNED','EXCHANGED','CANCEL_REQUEST','RETURN_REQUEST','CANCEL_DONE'];
const result = {};

if (!token) {
  return [{ json: { naver: result, error: $('네이버 인증').first().json.error || 'No token' } }];
}

for (const dt of dateInfo.dates) {
  const from = dt + 'T00:00:00.000%2B09:00';
  const to = dt + 'T23:59:59.999%2B09:00';

  try {
    const data = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://api.commerce.naver.com/external/v1/pay-order/seller/product-orders?from=' + from + '&to=' + to,
      headers: { Authorization: 'Bearer ' + token }
    });

    const contents = (data.data && data.data.contents) || [];
    let revenue = 0, orders = 0;
    for (const item of contents) {
      const po = item.content && item.content.productOrder;
      if (!po) continue;
      if (CANCEL.includes(po.productOrderStatus || '')) continue;
      revenue += parseInt(po.totalPaymentAmount || 0);
      orders++;
    }
    result[dt] = { revenue, orders };
  } catch(e) {
    result[dt] = { revenue: -1, orders: -1, error: e.message };
  }
}

return [{ json: { naver: result } }];

// 11번가 최근 기간 재조회: 주문 상태별 매출 + 클레임 차감 후보
// 기존 /completed만 보면 아직 구매확정 전이거나 배송완료 상태인 주문을 놓친다.
const apiKey = $env.ST11_API_KEY || '';
const dateInfo = $('날짜 계산').first().json;

if (!apiKey) {
  return [{ json: { claimsByDate: {}, completedByDate: {}, summary: {}, errors: ['ST11_API_KEY 미설정'] } }];
}

const dates = dateInfo.dates || [];
const dateSet = new Set(dates);
const errors = [];
const completedByDate = {};
const claimsByDate = {};
const summary = { order: { count: 0, amount: 0 }, cancel: { count: 0, amount: 0 }, return: { count: 0, amount: 0 }, exchange: { count: 0, amount: 0 } };

const num = (v) => {
  if (v === undefined || v === null || v === '') return 0;
  const s = String(v).replace(/[^0-9.-]/g, '');
  return parseInt(s) || 0;
};
const get = (chunk, f) => {
  const re = new RegExp('<(?:ns2:)?' + f + '>([\\s\\S]*?)</(?:ns2:)?' + f + '>', 'i');
  const m = chunk.match(re);
  return m ? String(m[1] || '').replace(/<!\[CDATA\[|\]\]>/g, '').trim() : '';
};
const date10 = (v) => {
  const s = String(v || '');
  if (/^\d{4}-\d{2}-\d{2}/.test(s)) return s.slice(0, 10);
  if (/^\d{4}\d{2}\d{2}/.test(s)) return s.slice(0, 4) + '-' + s.slice(4, 6) + '-' + s.slice(6, 8);
  return '';
};
const pickAmount = (chunk) => num(get(chunk, 'ordAmt')) || num(get(chunk, 'ordPayAmt')) || num(get(chunk, 'prdPayAmt')) || num(get(chunk, 'selPrc'));
const addRevenue = (dt, amount) => {
  if (!completedByDate[dt]) completedByDate[dt] = { revenue: 0, orders: 0 };
  completedByDate[dt].revenue += amount;
  completedByDate[dt].orders += 1;
  summary.order.count += 1;
  summary.order.amount += amount;
};

// windows: 7일 단위로 쪼개기
const windows = [];
for (let i = 0; i < dates.length; i += 7) {
  const s = dates[i].replace(/-/g, '') + '0000';
  const e = dates[Math.min(i + 6, dates.length - 1)].replace(/-/g, '') + '2359';
  windows.push([s, e]);
}
const endpoints = ['complete', 'packaging', 'shipping', 'dlvcompleted', 'completed', 'reservatecomplete'];
const seen = new Set();

for (const ep of endpoints) {
  for (const [s, e] of windows) {
    try {
      const resp = await this.helpers.httpRequest({ method: 'GET', url: 'https://api.11st.co.kr/rest/ordservices/' + ep + '/' + s + '/' + e, headers: { openapikey: apiKey }, encoding: 'utf-8', timeout: 20000 });
      const xmlStr = typeof resp === 'string' ? resp : JSON.stringify(resp);
      if (xmlStr.includes('조회된 결과가 없습니다') || xmlStr.includes('해당 건이 없습니다')) continue;
      const orderMatches = xmlStr.match(/<(?:ns2:)?order>[\s\S]*?<\/(?:ns2:)?order>/g) || [];
      for (const chunk of orderMatches) {
        const dt = date10(get(chunk, 'ordDt'));
        if (!dateSet.has(dt)) continue;
        const ordNo = get(chunk, 'ordNo');
        const seq = get(chunk, 'ordPrdSeq');
        const key = ordNo + '_' + seq;
        if (seen.has(key)) continue;
        const amount = pickAmount(chunk);
        if (amount <= 0) continue;
        seen.add(key);
        addRevenue(dt, amount);
      }
    } catch(e) { errors.push(ep + ': ' + e.message); }
  }
}

// 클레임 완료/신청 3종: 주문일 기준으로 기존 매출에서 차감할 후보
const claimTypes = [
  ['canceledorders', 'cancel'], ['cancelorders', 'cancel'],
  ['returnedorders', 'return'], ['returnorders', 'return'],
  ['exchangedorders', 'exchange'], ['exchangeorders', 'exchange'],
];
for (const [type, label] of claimTypes) {
  for (const [s, e] of windows) {
    try {
      const resp = await this.helpers.httpRequest({ method: 'GET', url: 'https://api.11st.co.kr/rest/claimservice/' + type + '/' + s + '/' + e, headers: { openapikey: apiKey }, encoding: 'utf-8', timeout: 20000 });
      const xmlStr = typeof resp === 'string' ? resp : JSON.stringify(resp);
      if (xmlStr.includes('조회된 결과가 없습니다') || xmlStr.includes('해당 건이 없습니다')) continue;
      const orderMatches = xmlStr.match(/<(?:ns2:)?order>[\s\S]*?<\/(?:ns2:)?order>/g) || [];
      for (const chunk of orderMatches) {
        const dt = date10(get(chunk, 'ordDt'));
        if (!dateSet.has(dt)) continue;
        const amount = pickAmount(chunk);
        if (amount <= 0) continue;
        if (!claimsByDate[dt]) claimsByDate[dt] = { amount: 0, count: 0 };
        claimsByDate[dt].amount += amount;
        claimsByDate[dt].count += 1;
        summary[label].count += 1;
        summary[label].amount += amount;
      }
    } catch(e) { errors.push(label + ':' + type + ': ' + e.message); }
  }
}

return [{ json: { claimsByDate, completedByDate, summary, errors, source: 'st11_multi_status_backfill' } }];

// NocoDB 기존 데이터 조회 -> 비교 -> PATCH -> Sheets 데이터 + 리포트 생성
const dateInfo = $('날짜 계산').first().json;
const ms = $('메이크샵 재조회').first().json.makeshop || {};
const nv = $('네이버 재조회').first().json.naver || {};
const claimData = $('11번가 클레임 조회').first().json;
const claimsByDate = claimData.claimsByDate || {};
const claimSummary = claimData.summary || {};
const claimErrors = claimData.errors || [];
const token = $env.NOCODB_TOKEN || '';

// 모든 관련 날짜 수집 (14일 + 클레임 주문일)
const allDates = new Set(dateInfo.dates);
for (const dt of Object.keys(claimsByDate)) allDates.add(dt);
const sortedDates = [...allDates].sort();

// NocoDB 기존 데이터
const records = {};
if (sortedDates.length > 0 && token) {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://nocodb.pressco21.com/api/v1/db/data/noco/pbmo0os7rnvfd48/mwxvxjiqtw177xu',
      headers: { 'xc-token': token },
      qs: {
        where: '(report_date,gte,' + sortedDates[0] + ')~and(report_date,lte,' + sortedDates[sortedDates.length - 1] + ')',
        limit: 100,
        fields: 'Id,report_date,makeshop_revenue,makeshop_orders,naver_revenue,naver_orders,st11_revenue,st11_orders,coupang_revenue,coupang_orders,crm_revenue,crm_orders,rocket_revenue,total_revenue,total_orders'
      }
    });
    for (const row of (resp.list || [])) records[row.report_date] = row;
  } catch(e) {}
}

// 변경 감지
const adjustments = [];
let totalMsDiff = 0, totalNvDiff = 0, totalStDiff = 0;
let msChangeDays = 0, nvChangeDays = 0, stChangeDays = 0;

for (const dt of sortedDates) {
  const ex = records[dt];
  if (!ex) continue;

  const patch = {};
  let hasChange = false;
  let msD = 0, nvD = 0, stD = 0;

  // 메이크샵
  if (ms[dt] && ms[dt].revenue >= 0) {
    const oldV = parseInt(ex.makeshop_revenue) || 0;
    const newV = ms[dt].revenue;
    if (oldV !== newV) {
      patch.makeshop_revenue = newV;
      patch.makeshop_orders = ms[dt].orders;
      msD = newV - oldV;
      totalMsDiff += msD;
      msChangeDays++;
      hasChange = true;
    }
  }

  // 네이버
  if (nv[dt] && nv[dt].revenue >= 0) {
    const oldV = parseInt(ex.naver_revenue) || 0;
    const newV = nv[dt].revenue;
    if (oldV !== newV) {
      patch.naver_revenue = newV;
      patch.naver_orders = nv[dt].orders;
      nvD = newV - oldV;
      totalNvDiff += nvD;
      nvChangeDays++;
      hasChange = true;
    }
  }

  // 11번가: /completed 구매확정 백필 (우선) + 클레임 차감
  const completedData = $('11번가 클레임 조회').first().json.completedByDate || {};
  if (completedData[dt] && completedData[dt].revenue > 0) {
    const oldV = parseInt(ex.st11_revenue) || 0;
    const newV = completedData[dt].revenue;
    if (newV > oldV) {
      patch.st11_revenue = newV;
      patch.st11_orders = completedData[dt].orders;
      stD = newV - oldV;
      totalStDiff += stD;
      stChangeDays++;
      hasChange = true;
    }
  } else if (claimsByDate[dt] && claimsByDate[dt].amount > 0) {
    const oldV = parseInt(ex.st11_revenue) || 0;
    const sub = claimsByDate[dt].amount;
    const newV = Math.max(0, oldV - sub);
    if (newV !== oldV) {
      patch.st11_revenue = newV;
      patch.st11_orders = Math.max(0, (parseInt(ex.st11_orders) || 0) - claimsByDate[dt].count);
      stD = newV - oldV;
      totalStDiff += stD;
      stChangeDays++;
      hasChange = true;
    }
  }

  if (hasChange) {
    const msR = patch.makeshop_revenue !== undefined ? patch.makeshop_revenue : (parseInt(ex.makeshop_revenue) || 0);
    const nvR = patch.naver_revenue !== undefined ? patch.naver_revenue : (parseInt(ex.naver_revenue) || 0);
    const stR = patch.st11_revenue !== undefined ? patch.st11_revenue : (parseInt(ex.st11_revenue) || 0);
    const cpR = parseInt(ex.coupang_revenue) || 0;
    const crmR = parseInt(ex.crm_revenue) || 0;
    const rktR = parseInt(ex.rocket_revenue) || 0;
    patch.total_revenue = msR + nvR + stR + cpR + crmR + rktR;

    const msO = patch.makeshop_orders !== undefined ? patch.makeshop_orders : (parseInt(ex.makeshop_orders) || 0);
    const nvO = patch.naver_orders !== undefined ? patch.naver_orders : (parseInt(ex.naver_orders) || 0);
    const stO = patch.st11_orders !== undefined ? patch.st11_orders : (parseInt(ex.st11_orders) || 0);
    const cpO = parseInt(ex.coupang_orders) || 0;
    const crmO = parseInt(ex.crm_orders) || 0;
    patch.total_orders = msO + nvO + stO + cpO + crmO;

    adjustments.push({ date: dt, id: ex.Id, patch, diffs: { ms: msD, nv: nvD, st: stD } });
  }
}

// NocoDB PATCH
let ok = 0, fail = 0;
for (const adj of adjustments) {
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: 'https://nocodb.pressco21.com/api/v1/db/data/noco/pbmo0os7rnvfd48/mwxvxjiqtw177xu/' + adj.id,
      headers: { 'xc-token': token, 'Content-Type': 'application/json' },
      body: adj.patch
    });
    ok++;
  } catch(e) { fail++; }
}

// Sheets 배치 데이터
const sheetsData = [];
for (const adj of adjustments) {
  const p = adj.date.split('-').map(Number);
  const target = new Date(Date.UTC(p[0], p[1]-1, p[2]));
  const jan1 = new Date(Date.UTC(2026, 0, 1));
  const row = Math.round((target - jan1) / 86400000) + 2;

  const ex = records[adj.date];
  const msV = adj.patch.makeshop_revenue !== undefined ? adj.patch.makeshop_revenue : (parseInt(ex.makeshop_revenue) || 0);
  const nvV = adj.patch.naver_revenue !== undefined ? adj.patch.naver_revenue : (parseInt(ex.naver_revenue) || 0);
  const stV = adj.patch.st11_revenue !== undefined ? adj.patch.st11_revenue : (parseInt(ex.st11_revenue) || 0);

  sheetsData.push({ range: '\uc77c\ubcc4 \ub9e4\ucd9c!C' + row + ':E' + row, values: [[msV, nvV, stV]] });
}

// 리포트 생성
const fmt = (n) => n.toLocaleString('ko-KR');
let rpt = '<b>[\uD83D\uDCCB \uc8FC\uAC04 \uC815\uC0B0 \uC870\uC815]</b>\n';
rpt += dateInfo.startStr + ' ~ ' + dateInfo.endStr + '\n';
rpt += '\u2501'.repeat(19) + '\n\n';

if (adjustments.length === 0) {
  rpt += '\u2705 \uBCC0\uACBD \uC5C6\uC74C\n';
  rpt += dateInfo.days + '\uC77C\uAC04 \uC804 \uCC44\uB110 \uB370\uC774\uD130 \uC77C\uCE58.\n';
} else {
  rpt += '\uD83D\uDCCB \uC870\uC815 ' + adjustments.length + '\uAC74:\n\n';
  if (msChangeDays > 0) rpt += '\uD83C\uDFEA \uBA54\uC774\uD06C\uC0F5: ' + msChangeDays + '\uC77C ' + (totalMsDiff >= 0 ? '+' : '') + fmt(totalMsDiff) + '\uC6D0\n';
  if (nvChangeDays > 0) rpt += '\uD83D\uDFE2 \uB124\uC774\uBC84: ' + nvChangeDays + '\uC77C ' + (totalNvDiff >= 0 ? '+' : '') + fmt(totalNvDiff) + '\uC6D0\n';
  if (stChangeDays > 0) rpt += '\uD83D\uDD34 11\uBC88\uAC00: ' + stChangeDays + '\uC77C ' + (totalStDiff >= 0 ? '+' : '') + fmt(totalStDiff) + '\uC6D0\n';

  const totalDiff = totalMsDiff + totalNvDiff + totalStDiff;
  rpt += '\n\uD83D\uDCB0 \uC21C \uC870\uC815: ' + (totalDiff >= 0 ? '+' : '') + fmt(totalDiff) + '\uC6D0\n';
  rpt += 'NocoDB ' + ok + '\uAC74 \uBC18\uC601';
  if (fail > 0) rpt += ' (' + fail + '\uAC74 \uC2E4\uD328)';
  rpt += '\n';
}

// 11번가 클레임+구매확정 요약
const cs = claimSummary;
const hasClaims = (cs.cancel && cs.cancel.count > 0) || (cs.return && cs.return.count > 0) || (cs.exchange && cs.exchange.count > 0);
if (hasClaims) {
  rpt += '\n\uD83D\uDCCA 11\uBC88\uAC00 \uD074\uB808\uC784 (7\uC77C):\n';
  if (cs.cancel && cs.cancel.count > 0) rpt += '  \u274C \uCDE8\uC18C ' + cs.cancel.count + '\uAC74 ' + fmt(cs.cancel.amount) + '\uC6D0\n';
  if (cs.return && cs.return.count > 0) rpt += '  \u21A9\uFE0F \uBC18\uD488 ' + cs.return.count + '\uAC74 ' + fmt(cs.return.amount) + '\uC6D0\n';
  if (cs.exchange && cs.exchange.count > 0) rpt += '  \uD83D\uDD04 \uAD50\uD658 ' + cs.exchange.count + '\uAC74 ' + fmt(cs.exchange.amount) + '\uC6D0\n';
}
if (cs.completed && cs.completed.count > 0) {
  rpt += '\n\u2705 11\uBC88\uAC00 \uAD6C\uB9E4\uD655\uC815 \uBC31\uD544:\n';
  rpt += '  ' + cs.completed.count + '\uAC74 ' + fmt(cs.completed.amount) + '\uC6D0 \uBC18\uC601\n';
}

if (claimErrors.length > 0) {
  rpt += '\n\u26A0\uFE0F 11\uBC88\uAC00 API: ' + claimErrors.join(', ') + '\n';
}

return [{ json: {
  chatId: dateInfo.chatId,
  report: rpt,
  adjustmentCount: adjustments.length,
  sheetsBody: JSON.stringify({ valueInputOption: 'USER_ENTERED', data: sheetsData }),
  totalDiff: totalMsDiff + totalNvDiff + totalStDiff,
  ok, fail
} }];
